script:
export const meta = {
  name: 'pi_plugins_audit',
  description: 'Audit current pi plugins, subagents config, and project workflow to recommend changes',
  phases: [
    { title: 'Inventory' },
    { title: 'Skill Analysis' },
    { title: 'Project Workflow' },
    { title: 'Synthesis' }
  ]
};

phase('Inventory');

// 1. Discover installed agents and chains
const agents = agent('List all available subagents and chains. Run: `pi agent list` or check the pi config directory for agent definitions. Also check if there are any project-level agents defined. Look in ~/.pi/agent/ and in the current project directory for any .pi/ or agent config files. Report everything you find — agent names, packages, models, descriptions, scope (user/project).', { label: 'agent inventory', model: 'openrouter/qwen/qwen3.6-27b' });

// 2. Read the pi-subagents skill file
const skill = agent('Read the pi-subagents skill file at C:\\Users\\user\\.pi\\agent\\npm\\node_modules\\pi-subagents\\skills\\pi-subagents\\SKILL.md and summarize its capabilities, when to use subagents vs workflow, and key patterns.', { label: 'skill analysis', model: 'openrouter/qwen/qwen3.6-27b' });

phase('Project Workflow');

// 3. Read project instructions and understand the workflow
const projectContext = agent('Read these files and summarize the agent workflow described in them:\n1. D:\\Documents\\AGENTS.md — focus on MIKO agent, subagent usage patterns, acceptance contracts, complexity levels\n2. D:\\Documents\\Repositories\\xkeen-ui\\CLAUDE.md — focus on project structure, build commands, testing patterns\n\nReport: what agents are defined, what delegation patterns exist, how testing and code quality work.', { label: 'project context', model: 'openrouter/qwen/qwen3.6-27b' });

// 4. Check actual pi config files
const piConfig = agent('Explore the pi configuration. Check:\n1. ~/.pi/ directory structure (ls -la recursively, but max depth 3)\n2. Any config.yaml, config.json, or .pi files in D:\\Documents\\Repositories\\xkeen-ui\\\n3. Check if there is a .pi directory in the project root\n4. Look for any custom agent definitions or chain configs\nReport everything found about the pi setup.', { label: 'pi config check', model: 'openrouter/qwen/qwen3.6-27b' });

phase('Synthesis');

// 5. Analyze and synthesize recommendations
const synthesis = agent(`You are an expert in pi-coding-agent configuration. Based on the following context, provide a detailed analysis and recommendations.

CONTEXT:
- Agents discovered: ${agents}
- Pi-subagents skill summary: ${skill}
- Project workflow: ${projectContext}
- Pi config: ${piConfig}

QUESTIONS TO ANSWER:

1. **Current State**: What subagents/chains are currently configured? Which are actually used in the project workflow?

2. **pi-subagents vs workflow**: The project AGENTS.md describes using subagent() calls (MIKO agent, etc.) while the pi-subagents skill also exists. Are these complementary or redundant? Can they coexist?

3. **MIKO Agent Analysis**: Is MIKO properly configured? What model does it use? Is that model in the available model list? (Available models include many OpenRouter and AWS Bedrock models)

4. **Redundancies**: What overlaps exist between the skill and project-level instructions?

5. **Improvements**:
   - What agents/chains should be added or removed?
   - Are there better models for specific tasks?
   - Should acceptance contracts be standardized?
   - What about the scout/planner/reviewer roles mentioned in AGENTS.md — are they defined as agents?

6. **Recommendation**: Should pi-subagents be kept, removed, or modified? What specific changes to AGENTS.md would improve the workflow?

Provide a structured report with clear actionable items.`, { label: 'synthesis recommendations' });
